package com.example.api.service;

import com.example.api.model.Item;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import jakarta.annotation.PostConstruct;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class ItemService {

    private static final Logger logger = LoggerFactory.getLogger(ItemService.class);

    private final Map<Long, Item> itemStore = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(0);

    @PostConstruct
    public void init() {
        logger.info("Initializing ItemService with sample data");
        createItem(new Item(null, "Widget", "A standard widget", 9.99));
        createItem(new Item(null, "Gadget", "A fancy gadget", 24.99));
        createItem(new Item(null, "Doohickey", "A useful doohickey", 14.50));
        logger.info("ItemService initialized with {} items", itemStore.size());
    }

    public List<Item> getAllItems() {
        logger.info("Retrieving all items from store");
        List<Item> items = new ArrayList<>(itemStore.values());
        logger.info("Retrieved {} items successfully", items.size());
        return items;
    }

    public Optional<Item> getItemById(Long id) {
        logger.info("Retrieving item with id={}", id);
        Optional<Item> item = Optional.ofNullable(itemStore.get(id));
        if (item.isPresent()) {
            logger.info("Item found: {}", item.get());
        } else {
            logger.warn("Item with id={} not found", id);
        }
        return item;
    }

    public Item createItem(Item item) {
        Long id = idGenerator.incrementAndGet();
        item.setId(id);
        itemStore.put(id, item);
        logger.info("Created new item: {} with id={}", item.getName(), id);
        return item;
    }

    public Optional<Item> updateItem(Long id, Item updatedItem) {
        logger.info("Updating item with id={}", id);
        if (!itemStore.containsKey(id)) {
            logger.warn("Cannot update item with id={}: not found", id);
            return Optional.empty();
        }
        updatedItem.setId(id);
        itemStore.put(id, updatedItem);
        logger.info("Item with id={} updated successfully", id);
        return Optional.of(updatedItem);
    }

    public boolean deleteItem(Long id) {
        logger.info("Deleting item with id={}", id);
        Item removed = itemStore.remove(id);
        if (removed != null) {
            logger.info("Item with id={} deleted successfully", id);
            return true;
        } else {
            logger.warn("Cannot delete item with id={}: not found", id);
            return false;
        }
    }
}

