package com.example.api.controller;

import com.example.api.model.Item;
import com.example.api.service.ItemService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/items")
public class ItemController {

    private static final Logger logger = LoggerFactory.getLogger(ItemController.class);

    private final ItemService itemService;

    public ItemController(ItemService itemService) {
        this.itemService = itemService;
        logger.info("ItemController initialized");
    }

    @GetMapping
    public ResponseEntity<List<Item>> getAllItems() {
        logger.info("GET /api/items - Fetching all items");
        List<Item> items = itemService.getAllItems();
        logger.info("GET /api/items - Returning {} items", items.size());
        return ResponseEntity.ok(items);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Object> getItemById(@PathVariable Long id) {
        logger.info("GET /api/items/{} - Fetching item by id", id);
        return itemService.getItemById(id)
                .map(item -> {
                    logger.info("GET /api/items/{} - Item found, returning 200", id);
                    return ResponseEntity.ok((Object) item);
                })
                .orElseGet(() -> {
                    logger.warn("GET /api/items/{} - Item not found, returning 404", id);
                    return ResponseEntity.status(HttpStatus.NOT_FOUND)
                            .body(Map.of("error", "Item not found", "id", id));
                });
    }

    @PostMapping
    public ResponseEntity<Item> createItem(@RequestBody Item item) {
        logger.info("POST /api/items - Creating new item: name={}", item.getName());
        Item created = itemService.createItem(item);
        logger.info("POST /api/items - Item created successfully with id={}", created.getId());
        return ResponseEntity.status(HttpStatus.CREATED).body(created);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Object> updateItem(@PathVariable Long id, @RequestBody Item item) {
        logger.info("PUT /api/items/{} - Updating item", id);
        return itemService.updateItem(id, item)
                .map(updated -> {
                    logger.info("PUT /api/items/{} - Item updated successfully", id);
                    return ResponseEntity.ok((Object) updated);
                })
                .orElseGet(() -> {
                    logger.warn("PUT /api/items/{} - Item not found, returning 404", id);
                    return ResponseEntity.status(HttpStatus.NOT_FOUND)
                            .body(Map.of("error", "Item not found", "id", id));
                });
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Object> deleteItem(@PathVariable Long id) {
        logger.info("DELETE /api/items/{} - Deleting item", id);
        if (itemService.deleteItem(id)) {
            logger.info("DELETE /api/items/{} - Item deleted successfully", id);
            return ResponseEntity.ok(Map.of("message", "Item deleted successfully", "id", id));
        } else {
            logger.warn("DELETE /api/items/{} - Item not found, returning 404", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(Map.of("error", "Item not found", "id", id));
        }
    }
}

